  ('generalpolice-3218f787-moex-00099', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-90de4de6', 'sub-generalpolice-3218f787-06', NULL, 'essay', '暑假將屆，為了提升青少年犯罪防制成效，內政部想要了解當前青少年
的休閒型態，現在委託您辦理一項研究工作，運用焦點團體訪談方法蒐
集資料。這項研究專案的辦理期程為一個月、經費預算 80萬元，針對各
縣市國高中辦理至少 40場焦點座談。請您提供一份服務建議書，內容包
含專案大綱與管理，敘述研究預定內容及範圍、資料蒐集方法、工作規
劃及預期成果等。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "70331ad0eaae", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0806", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會科學研究法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00100', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-696aa37c', 'sub-generalpolice-3218f787-07', NULL, 'essay', '你正在進行犯罪防治輔導，一位當事人因長期職場霸凌而陷入報復的強
烈情緒，並已開始思考極端行為。請運用羅傑斯（Carl Rogers）個人中
心治療的三大核心條件（一致性、無條件的正向關懷與接納、精確的同
理心理解），依序說明：你如何解讀這三大條件在理論上的核心意義？
你會如何將這三項條件具體運用於與該當事人的輔導過程中，協助其
處理情緒、重建自尊，並降低其偏差風險？在每項核心條件的說明中，
各舉出一個輔導人員與當事人之間的具體對話實例，以展現該核心條件
在實際輔導過程中的運用。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "c95d3237f37a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0810", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "諮商與輔導", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00101', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-696aa37c', 'sub-generalpolice-3218f787-07', NULL, 'essay', '研究發現，反社會型人格障礙（antisocialpersonalitydisorder,ASPD）與
多種犯罪行為存在顯著關聯，這在犯罪防治領域具有重要意義。根據診
斷準則，反社會型人格障礙可從兩大面向加以界定與評估：人格功能的
典型減損情況（認同感 identity、自我指向 self-direction、同理心 empathy、
親密感 intimacy），以及病態人格特質。請詳細回答：從四大人格功能
的減損角度，分析反社會型人格障礙者的典型表現。請依據五大病態
人格特質的領域，闡述反社會型人格障礙者的特徵表現。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "c95d3237f37a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0810", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "諮商與輔導", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00102', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-696aa37c', 'sub-generalpolice-3218f787-07', NULL, 'essay', '警察工作具高度壓力與風險，維護警察人員的心理健康對其執勤效能與
生活品質就顯得格外重要。假設你是警察局「心理輔導室」的主任，需
設計一套針對警察人員特殊需求的正念減壓課程（mindfulness-based
stress reduction, MBSR ）。 請依序 回答下 列問題 ：何 謂正念
（mindfulness）？請說明其核心概念與原理，以及為何正念練習適合用
於警察人員的情緒管理與壓力調適。請詳細說明正念減壓課程中的
「身體掃描冥想」（bodyscanmeditation）的執行步驟和具體技巧。請
設計一個完整、具體且符合警察工作特性的八週正念減壓課程大綱，內
容應包含每週的主題與目標、課程內容與活動介紹等。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "c95d3237f37a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0810", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "諮商與輔導", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00103', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-114-696aa37c', 'sub-generalpolice-3218f787-07', NULL, 'essay', '警察人員常須處理有自我傷害風險的當事人，這需要專業的溝通技巧，
更需具備有效的心理支持能力。辯證行為治療（dialectical behavior
therapy,DBT）提供了四項核心技巧，可有效應用於此類危機處理。假設
你是接受過 DBT訓練的警察心理輔導員，請回答：說明 DBT四大核
心技巧的基本概念和主要內涵，並解釋為何這些技巧適合用於處理自我
傷害危機。針對每項DBT核心技巧，具體提出兩個實用的策略或方法。
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "c95d3237f37a", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "302", "s": "0810", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "諮商與輔導", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00104', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '下列敘述，何者沒有冗詞贅語？', '["這箱東西顯得太重了，我無法拿得起來", "選舉投票日將屆，各候選人無不卯足全力衝刺，以爭取更多選票", "捷運上午接二連三發生跳電二十多分鐘的情況不斷持續，許多旅客等了半小時還 等不到車", "關於本次美軍空襲阿富汗的事件，記者在現場為您轉播來自 CNN的本臺第一手 獨家新聞報導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
  ('generalpolice-3218f787-moex-00105', 'generalpolice-3218f787', 'generalpolice-3218f787-moex-113-13504c0c', 'sub-generalpolice-3218f787-02', NULL, 'single_choice', '「在狂暴自然與無情時間中消磨，千年來屹立不搖的努比亞金字塔，最後毀在人性 的貪婪與無知。一八三四年一名來自義大利、曾經加入蘇丹遠征軍的盜墓者費里尼， 在喀土穆服役期間，聽說沙漠中藏有許多未經發掘的古代寶藏，財迷心竅的他竟然 跑去說服當地統治者蘇丹總督，總督本人就是聲名狼藉的奴隸販子，對於異教徒所 遺留的偉大建築毫無感情可言，當然也不在乎金字塔即將面臨的悲劇。取得許可後 的費里尼帶了一大批工人，開始以不專業的手法在美羅埃挖掘。」 根據上文，下列敘述何者錯誤？', '["破壞努比亞金字塔的是義大利人", "努比亞金字塔位於蘇丹境內的沙漠之中", "當時總督為了錢，並不反對挖掘金字塔", "努比亞金字塔毀於時間的無情與人性的貪婪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:30+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "303", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL)
